import{_ as i,c as a,o as t,ae as s}from"./chunks/framework.Cd-3tpCq.js";const n="/assets/drupal-installation-01.B6J8HGwQ.png",o="/assets/drupal-installation-02.Bhw9dhHx.png",l="/assets/drupal-installation-03.T2ZsQk3Z.png",r="/assets/drupal-installation-04.CZly3F-p.png",q=JSON.parse('{"title":"💧 Initialisation du site Drupal","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/init.md","filePath":"drupal-project/installation/init.md"}'),u={name:"drupal-project/installation/init.md"};function p(d,e,c,m,g,h){return t(),a("div",null,e[0]||(e[0]=[s('<h1 id="💧-initialisation-du-site-drupal" tabindex="-1">💧 Initialisation du site Drupal <a class="header-anchor" href="#💧-initialisation-du-site-drupal" aria-label="Permalink to &quot;💧 Initialisation du site Drupal&quot;">​</a></h1><p>L&#39;installation de <strong>Drupal</strong> via <strong>Composer</strong> avec la commande <code>create-project</code> ne constitue que la première étape du processus de mise en place d&#39;un site <strong>Drupal</strong> fonctionnel. Cette commande télécharge uniquement les fichiers source du framework et ses dépendances <strong>PHP</strong>, mais elle ne crée pas encore un site opérationnel.</p><p>Pour finaliser cette installation, <strong>Drupal</strong> propose une interface graphique.</p><p>Utilisez cette commande pour vous rendre sur l&#39;interface d&#39;installation :</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ddev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> launch</span></span></code></pre></div><h2 id="les-etapes-de-l-initialisation" tabindex="-1">Les étapes de l&#39;initialisation <a class="header-anchor" href="#les-etapes-de-l-initialisation" aria-label="Permalink to &quot;Les étapes de l&#39;initialisation&quot;">​</a></h2><p>Détaillons ensemble les étapes d&#39;initialisation de <strong>Drupal</strong>.</p><h3 id="_1-choose-language" tabindex="-1">1. Choose language <a class="header-anchor" href="#_1-choose-language" aria-label="Permalink to &quot;1. Choose language&quot;">​</a></h3><p><img src="'+n+'" alt="Initialisation de Drupal - Choisir la langue"><em>Initialisation de Drupal - Choisir la langue</em></p><p>Ce premier écran de l&#39;initialisation de <strong>Drupal</strong> vous propose de sélectionner la langue, avec le français sélectionné par défaut.</p><p>Bien qu&#39;il soit tentant d&#39;installer directement <strong>Drupal</strong> dans sa langue natale, je recommande de procéder à l&#39;installation initiale en anglais. Il est bien entendu possible de télécharger des packs de langues par la suite.</p><p>Les raisons sont :</p><ul><li><strong>Traductions incomplètes</strong> : certains textes peuvent rester en anglais si les traductions ne sont pas à 100%.</li><li><strong>Modules contribués</strong> : beaucoup n&#39;ont pas de traductions françaises disponibles immédiatement.</li><li><strong>Formation simplifiée</strong> : de nombreux tutos sont en anglais, il sera plus simple de suivre ces tutos avec une interface identique.</li><li><strong>Debug plus simple</strong> : les messages d&#39;erreurs seront en anglais ce qui facilite la recherche sur <strong>Google</strong> ou la documentation.</li></ul><p>Il n&#39;y a pas vraiment de risque ou de problème à charger une autre langue que l&#39;anglais. Je trouve juste cela plus pratique.</p><p>Je vous invite donc à choisir &quot;English&quot; dans la liste et de valider le formulaire en cliquant sur le bouton &quot;Save and continue&quot;.</p><h3 id="_2-choose-profile" tabindex="-1">2. Choose profile <a class="header-anchor" href="#_2-choose-profile" aria-label="Permalink to &quot;2. Choose profile&quot;">​</a></h3><p><img src="'+o+'" alt="Initialisation de Drupal - Choisir le profil"><em>Initialisation de Drupal - Choisir le profil</em></p><p>Cet écran de l&#39;initialisation nous propose de choisir quel profil d&#39;installation nous souhaitons utiliser pour la configuration de base de notre site. Chaque profil pré-configure différents modules, types de contenu, rôles utilisateurs et paramètres selon un usage spécifique.</p><ul><li><strong>Standard</strong> : configuration polyvalente avec des fonctionnalités courantes (articles, pages, commentaires, taxonomie). Idéal pour la plupart des sites web classiques.</li><li><strong>Minimal</strong> : installation très légère avec seulement les modules indispensables. Parfait lorsque l&#39;on souhaite construire notre site de zéro.</li><li><strong>Demo Umami Food Magazine</strong> : site de démonstration pré-rempli avec du contenu d&#39;exemple. Utile pour découvrir les possibilités de Drupal ou comme base pour un site magazine.</li></ul><p>Par défaut j&#39;aurais tendance à proposer le profil <strong>Standard</strong>. Mais pour cette formation nous allons effectuer l&#39;installation avec le profil <strong>Minimal</strong>.</p><p>La première raison est que ça nous donnera l&#39;occasion de voir un à un tous les modules principaux à la création d&#39;un site internet.</p><p>Et surtout, dans le cas où plusieurs développeurs auront à travailler sur le même projet <strong>Drupal</strong>, il faut pouvoir permettre l&#39;installation à partir des configurations existantes. Et ce n&#39;est possible qu&#39;en effectuant une installation minimale. (Sans avoir à effectuer des modifications dans les fichiers de configs).</p><p>Choisissez &quot;Minimal&quot; et validez le formulaire en cliquant sur &quot;Save and continue&quot;.</p><h3 id="_3-verify-requirements" tabindex="-1">3. Verify requirements <a class="header-anchor" href="#_3-verify-requirements" aria-label="Permalink to &quot;3. Verify requirements&quot;">​</a></h3><p>Vous n&#39;avez rien à faire durant cette étape. Elle est d&#39;ailleurs automatiquement validée.</p><h3 id="_4-set-up-database" tabindex="-1">4. Set up database <a class="header-anchor" href="#_4-set-up-database" aria-label="Permalink to &quot;4. Set up database&quot;">​</a></h3><p>Lors de l&#39;installation du projet avec <strong>DDEV</strong>, les informations de connexion à la base de données ont déjà été configurées dans les fichiers <em>settings</em> de <strong>Drupal</strong>. Nous les analyserons plus en détail plus tard dans la formation.</p><p>Vous n&#39;avez donc rien à faire durant cette étape.</p><h3 id="_5-install-site" tabindex="-1">5. Install site <a class="header-anchor" href="#_5-install-site" aria-label="Permalink to &quot;5. Install site&quot;">​</a></h3><p>Vous n&#39;avez rien à faire durant cette étape. Elle est d&#39;ailleurs automatiquement validée.</p><h3 id="_6-configure-site" tabindex="-1">6. Configure site <a class="header-anchor" href="#_6-configure-site" aria-label="Permalink to &quot;6. Configure site&quot;">​</a></h3><p><img src="'+l+'" alt="Initialisation de Drupal - Configurer le site"><em>Initialisation de Drupal - Configurer le site</em></p><p>Dernière étape de l&#39;initialisation de notre projet Drupal.</p><p>Il ne reste plus qu&#39;à indiquer les informations de notre site internet. Vous pouvez saisir les informations suivantes :</p><ul><li><strong>Site name</strong> : CinéCritique</li><li><strong>Site email address</strong> : <a href="mailto:contact@cineticritique.com" target="_blank" rel="noreferrer">contact@cineticritique.com</a> (pas besoin que l&#39;adresse mail soit valide car on utilisera un catcher de mail)</li><li><strong>SITE MAINTENANCE ACCOUNT</strong><ul><li><strong>Username</strong> : admin</li><li><strong>Password</strong> : password (nous sommes en local, pas besoin que le mot de passe soit sécurisé)</li><li><strong>Confirm password</strong> : password</li><li><strong>Email address</strong> : <a href="mailto:admin@cineticritique.com" target="_blank" rel="noreferrer">admin@cineticritique.com</a> (Ici aussi il n&#39;est pas nécessaire que l&#39;adresse mail soit valide)</li></ul></li><li><strong>REGIONAL SETTINGS</strong><ul><li><strong>Default time zone</strong> : Paris</li></ul></li><li><strong>UPDATE NOTIFICATIONS</strong> : <ul><li>Check for updates automatically : Activez cette option pour recevoir des notifications de mise à jour automatique.</li><li>Receive email notifications : Comme nous sommes en local, il n&#39;est pas nécessaire d&#39;activer cette option.</li></ul></li></ul><p>Une fois les informations entrées, validez le formulaire en cliquant sur &quot;Save and continue&quot;.</p><h2 id="felicitation" tabindex="-1">Félicitation <a class="header-anchor" href="#felicitation" aria-label="Permalink to &quot;Félicitation&quot;">​</a></h2><p><img src="'+r+'" alt="Initialisation de Drupal - Fin d&#39;installation"><em>Initialisation de Drupal - Fin d&#39;installation</em></p><p>Votre site <strong>Drupal</strong> est désormais installé et initialisé... et il est très moche !</p><p>Mais ne vous inquiétez pas, c&#39;est tout à fait normal. N&#39;oubliez pas que nous avons effectué une installation minimale. Nous n&#39;avons donc pas de contenu, ni de templates, ni de modules, etc..</p><div class="info custom-block"><p class="custom-block-title">Avant d&#39;installer notre tout premier module</p><p>Prenons un peu de temps pour analyser <a href="/drupal-project/installation/architecture.html">l&#39;architecture d&#39;un projet <strong>Drupal</strong></a>.</p></div>',41)]))}const v=i(u,[["render",p]]);export{q as __pageData,v as default};
